import{_ as n,o as s,c as i,ai as a}from"./chunks/framework.LYGRWSbL.js";const p=JSON.parse('{"title":"Les subordonnées","description":"","frontmatter":{},"headers":[],"relativePath":"module-5-aller-plus-loin/subordonnees.md","filePath":"module-5-aller-plus-loin/subordonnees.md","lastUpdated":1773298982000}'),o={name:"module-5-aller-plus-loin/subordonnees.md"};function r(t,e,l,d,u,m){return s(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="les-subordonnees" tabindex="-1">Les subordonnées <a class="header-anchor" href="#les-subordonnees" aria-label="Permalink to “Les subordonnées”">​</a></h1><p><strong>Prérequis :</strong> <a href="./adjectifs.html">Les adjectifs</a></p><p><strong>Objectif :</strong> construire des phrases complexes avec des propositions subordonnees - et maitriser le rejet du verbe en fin de proposition.</p><p>Les subordonnées permettent d&#39;expliquer, de justifier, de conditionner. Elles changent la position du verbe : dans une subordonnee, le verbe conjugue va en fin de proposition.</p><h2 id="la-regle-fondamentale" tabindex="-1">La règle fondamentale <a class="header-anchor" href="#la-regle-fondamentale" aria-label="Permalink to “La règle fondamentale”">​</a></h2><p>Dans une proposition subordonnée, le verbe conjugue se place <strong>en toute derniere position</strong>.</p><div class="mt-4 grid gap-3"><div class="p-4 rounded-xl border border-gray-200"><div class="font-medium text-gray-700 mb-2">Principale (V2 normal)</div><div class="font-mono text-sm"><span class="bg-blue-100 px-1 rounded">Ich lerne Deutsch</span><span class="bg-green-100 px-1 rounded ml-1">[verbe en pos. 2]</span></div><div class="text-sm text-gray-500 italic mt-1">J&#39;apprends l&#39;allemand.</div></div><div class="p-4 rounded-xl border border-gray-200"><div class="font-medium text-gray-700 mb-2">Subordonnee (verbe en fin)</div><div class="font-mono text-sm"><span class="bg-orange-100 px-1 rounded">weil</span><span class="bg-gray-100 px-1 rounded ml-1">ich in Deutschland</span><span class="bg-green-100 px-1 rounded ml-1">arbeite</span></div><div class="text-sm text-gray-500 italic mt-1">...parce que je travaille en Allemagne.</div></div></div><h2 id="les-conjonctions-de-subordination" tabindex="-1">Les conjonctions de subordination <a class="header-anchor" href="#les-conjonctions-de-subordination" aria-label="Permalink to “Les conjonctions de subordination”">​</a></h2><h3 id="weil-parce-que" tabindex="-1">weil - parce que <a class="header-anchor" href="#weil-parce-que" aria-label="Permalink to “weil - parce que”">​</a></h3><ul><li><em>Ich lerne Deutsch, <strong>weil</strong> ich in Deutschland <strong>arbeite</strong>.</em> - J&#39;apprends l&#39;allemand parce que je travaille en Allemagne.</li><li><em>Er geht schlafen, <strong>weil</strong> er mude <strong>ist</strong>.</em> - Il va dormir parce qu&#39;il est fatigue.</li></ul><h3 id="dass-que" tabindex="-1">dass - que <a class="header-anchor" href="#dass-que" aria-label="Permalink to “dass - que”">​</a></h3><ul><li><em>Ich glaube, <strong>dass</strong> er krank <strong>ist</strong>.</em> - Je crois qu&#39;il est malade.</li><li><em>Sie sagt, <strong>dass</strong> sie kommen <strong>will</strong>.</em> - Elle dit qu&#39;elle veut venir.</li></ul><h3 id="wenn-quand-si-conditionnel" tabindex="-1">wenn - quand / si (conditionnel) <a class="header-anchor" href="#wenn-quand-si-conditionnel" aria-label="Permalink to “wenn - quand / si (conditionnel)”">​</a></h3><ul><li><em>Ruf mich an, <strong>wenn</strong> du Zeit <strong>hast</strong>.</em> - Appelle-moi quand tu as le temps.</li><li><em><strong>Wenn</strong> es regnet, bleibe ich zu Hause.</em> - S&#39;il pleut, je reste a la maison.</li></ul><h3 id="obwohl-bien-que-meme-si" tabindex="-1">obwohl - bien que / même si <a class="header-anchor" href="#obwohl-bien-que-meme-si" aria-label="Permalink to “obwohl - bien que / même si”">​</a></h3><ul><li><em>Er ist gegangen, <strong>obwohl</strong> er krank <strong>war</strong>.</em> - Il est parti bien qu&#39;il etait malade.</li><li><em>Sie lacht, <strong>obwohl</strong> sie traurig <strong>ist</strong>.</em> - Elle rit même si elle est triste.</li></ul><h3 id="damit-pour-que-afin-que" tabindex="-1">damit - pour que / afin que <a class="header-anchor" href="#damit-pour-que-afin-que" aria-label="Permalink to “damit - pour que / afin que”">​</a></h3><ul><li><em>Ich spreche laut, <strong>damit</strong> du mich verstehen <strong>kannst</strong>.</em> - Je parlé fort pour que tu puisses me comprendre.</li></ul><h3 id="ob-si-interrogatif-indirect" tabindex="-1">ob - si (interrogatif indirect) <a class="header-anchor" href="#ob-si-interrogatif-indirect" aria-label="Permalink to “ob - si (interrogatif indirect)”">​</a></h3><ul><li><em>Ich weiß nicht, <strong>ob</strong> er <strong>kommt</strong>.</em> - Je ne sais pas s&#39;il vient.</li></ul><div class="warning custom-block"><p class="custom-block-title">weil vs denn</p><p>Les deux signifient &quot;parce que&quot;, mais leur syntaxe est différente. <em>denn</em> est une conjonction de coordination (position 0) : le verbe reste en position 2 dans la phrase qui suit. <em>weil</em> est une conjonction de subordination : le verbe va en fin de proposition. <em>Ich lerne Deutsch, <strong>denn</strong> ich <strong>wohne</strong> in Berlin.</em> (V2) <em>Ich lerne Deutsch, <strong>weil</strong> ich in Berlin <strong>wohne</strong>.</em> (verbe en fin)</p></div><h2 id="quand-la-subordonnee-est-en-position-1" tabindex="-1">Quand la subordonnee est en position 1 <a class="header-anchor" href="#quand-la-subordonnee-est-en-position-1" aria-label="Permalink to “Quand la subordonnee est en position 1”">​</a></h2><p>Si la subordonnee précède la principale, la principale commence directement par son verbe (toujours V2 dans la phrase entiere) :</p><ul><li><em><strong>Weil</strong> ich mude <strong>bin</strong>, gehe ich schlafen.</em> - Parce que je suis fatigue, je vais dormir.</li><li><em><strong>Wenn</strong> es regnet, <strong>bleibe</strong> ich zu Hause.</em> - S&#39;il pleut, je reste chez moi.</li></ul><div class="tip custom-block"><p class="custom-block-title">La virgule est obligatoire</p><p>En allemand, on met systématiquement une virgule avant une proposition subordonnée. Ce n&#39;est pas optionnel comme en français - c&#39;est une règle grammaticale.</p></div><h2 id="les-temps-composes-en-subordonnee" tabindex="-1">Les temps composes en subordonnee <a class="header-anchor" href="#les-temps-composes-en-subordonnee" aria-label="Permalink to “Les temps composes en subordonnee”">​</a></h2><p>Au Perfekt ou avec un modal, l&#39;auxiliaire ou le modal va en dernière position, et le participe ou l&#39;infinitif le précède immediatement :</p><ul><li><em>..., weil er das Buch <strong>gelesen hat</strong>.</em> - ...parce qu&#39;il a lu le livre.</li><li><em>..., weil sie kommen <strong>will</strong>.</em> - ...parce qu&#39;elle veut venir. (<em>will</em> = modal en fin)</li></ul>',28)])])}const g=n(o,[["render",r]]);export{p as __pageData,g as default};
